package com.example.bankapp;

import androidx.annotation.NonNull;
import androidx.room.Transaction;

import java.util.Locale;
import java.util.UUID;

public final class BankRepository {
    private final BankDatabase db;
    private final AccountDao accountDao;
    private final TransactionDao transactionDao;

    public BankRepository(@NonNull BankDatabase db, @NonNull AccountDao accountDao, @NonNull TransactionDao transactionDao) {
        this.db = db;
        this.accountDao = accountDao;
        this.transactionDao = transactionDao;
    }

    @Transaction
    public ProcessResult processTransaction(@NonNull ProcessRequest request) {
        if (request.accountId == null || request.accountId.trim().isEmpty()) {
            return ProcessResult.error("INVALID_ACCOUNT");
        }
        if (request.amountMinor <= 0) {
            return ProcessResult.error("INVALID_AMOUNT");
        }
        String type = normalizeType(request.type);
        if (type == null) {
            return ProcessResult.error("INVALID_TYPE");
        }

        String requestId = (request.requestId == null || request.requestId.trim().isEmpty())
                ? UUID.randomUUID().toString()
                : request.requestId.trim();

        return db.runInTransaction(() -> {
            if (transactionDao.countByRequestId(requestId) > 0) {
                AccountEntity a = accountDao.getAccountSync(request.accountId);
                if (a == null) return ProcessResult.error("ACCOUNT_NOT_FOUND");
                return ProcessResult.ok(requestId, a.balanceMinor, a.currency);
            }

            AccountEntity account = accountDao.getAccountSync(request.accountId);
            if (account == null) return ProcessResult.error("ACCOUNT_NOT_FOUND");

            long delta = type.equals("CREDIT") ? request.amountMinor : -request.amountMinor;
            long newBalance = safeAdd(account.balanceMinor, delta);

            if (type.equals("DEBIT") && newBalance < 0) {
                return ProcessResult.error("INSUFFICIENT_FUNDS");
            }

            long now = System.currentTimeMillis();
            TransactionEntity tx = new TransactionEntity(
                    requestId,
                    request.accountId,
                    type,
                    request.amountMinor,
                    now,
                    request.note
            );
            transactionDao.insert(tx);

            AccountEntity updated = new AccountEntity(
                    account.accountId,
                    account.displayName,
                    account.currency,
                    newBalance,
                    now
            );
            accountDao.upsert(updated);

            return ProcessResult.ok(requestId, newBalance, updated.currency);
        });
    }

    private static String normalizeType(String type) {
        if (type == null) return null;
        String t = type.trim().toUpperCase(Locale.US);
        if ("DEBIT".equals(t) || "CREDIT".equals(t)) return t;
        return null;
    }

    private static long safeAdd(long a, long b) {
        long r = a + b;
        if (((a ^ r) & (b ^ r)) < 0) {
            throw new ArithmeticException("long overflow");
        }
        return r;
    }
}

