package com.example.bankapp;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.text.NumberFormat;
import java.util.Currency;
import java.util.Locale;

public final class MoneyFormatter {
    private MoneyFormatter() {}

    public static String formatMinor(long minor, String currencyCode) {
        try {
            Currency c = currencyCode != null ? Currency.getInstance(currencyCode) : Currency.getInstance("USD");
            int fraction = c.getDefaultFractionDigits();
            BigDecimal amount = BigDecimal.valueOf(minor).movePointLeft(fraction);
            NumberFormat nf = NumberFormat.getCurrencyInstance(Locale.getDefault());
            nf.setCurrency(c);
            nf.setRoundingMode(RoundingMode.HALF_UP);
            return nf.format(amount);
        } catch (Exception e) {
            return String.valueOf(minor);
        }
    }
}

package com.example.bankapp;

import android.app.Application;

import androidx.annotation.NonNull;
import androidx.lifecycle.AndroidViewModel;
import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;

import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class AccountViewModel extends AndroidViewModel {
    private final BankRepository repo;
    private final ExecutorService io = Executors.newSingleThreadExecutor();

    private LiveData<AccountEntity> account;
    private LiveData<List<TransactionEntity>> recent;
    private final MutableLiveData<ProcessResult> lastResult = new MutableLiveData<>();

    public AccountViewModel(@NonNull Application application) {
        super(application);
        repo = AppContainer.get().repository;
    }

    public void load(@NonNull String accountId) {
        account = AppContainer.get().repository == null ? null : AppContainer.get().repository.db.accountDao().observeAccount(accountId);
        recent = AppContainer.get().repository == null ? null : AppContainer.get().repository.db.transactionDao().observeRecent(accountId, 20);
    }

    public LiveData<AccountEntity> account() { return account; }

    public LiveData<List<TransactionEntity>> recent() { return recent; }

    public LiveData<ProcessResult> lastResult() { return lastResult; }

    public void submit(@NonNull ProcessRequest request) {
        io.execute(() -> {
            ProcessResult r;
            try {
                r = repo.processTransaction(request);
            } catch (Exception e) {
                r = ProcessResult.error("PROCESSING_ERROR");
            }
            lastResult.postValue(r);
        });
    }

    @Override
    protected void onCleared() {
        io.shutdown();
    }
}

package com.example.bankapp;

import android.os.Bundle;
import android.text.InputType;
import android.view.Gravity;
import android.view.View;
import android.widget.ArrayAdapter;
import android.widget.Button;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.Spinner;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;

public class AccountActivity extends AppCompatActivity {
    public static final String EXTRA_ACCOUNT_ID = "account_id";

    private AccountViewModel vm;

    private TextView balanceView;
    private TextView nameView;
    private TextView statusView;
    private EditText amountView;
    private Spinner typeSpinner;
    private Button submitButton;

    private String accountId;
    private String currency = "USD";

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        accountId = getIntent() != null ? getIntent().getStringExtra(EXTRA_ACCOUNT_ID) : null;
        if (accountId == null) accountId = "demo";

        setContentView(buildUi());

        vm = new ViewModelProvider(this).get(AccountViewModel.class);

        ensureDemoAccount();

        vm.load(accountId);

        vm.account().observe(this, a -> {
            if (a == null) return;
            currency = a.currency != null ? a.currency : "USD";
            nameView.setText(a.displayName != null ? a.displayName : ("Account " + a.accountId));
            balanceView.setText(MoneyFormatter.formatMinor(a.balanceMinor, currency));
        });

        vm.lastResult().observe(this, r -> {
            if (r == null) return;
            if (r.success) {
                statusView.setText("Success. New balance: " + MoneyFormatter.formatMinor(r.newBalanceMinor, r.currency != null ? r.currency : currency));
            } else {
                statusView.setText("Failed: " + r.errorCode);
            }
        });

        submitButton.setOnClickListener(v -> {
            long amountMinor = parseAmountToMinor(amountView.getText() != null ? amountView.getText().toString() : "", currency);
            String type = String.valueOf(typeSpinner.getSelectedItem());
            ProcessRequest req = new ProcessRequest(accountId, type, amountMinor, null, null);
            vm.submit(req);
        });
    }

    private View buildUi() {
        int pad = (int) (getResources().getDisplayMetrics().density * 16);

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(pad, pad, pad, pad);
        root.setLayoutParams(new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.MATCH_PARENT
        ));

        nameView = new TextView(this);
        nameView.setTextSize(18f);
        root.addView(nameView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        TextView balanceLabel = new TextView(this);
        balanceLabel.setText("Balance");
        root.addView(balanceLabel);

        balanceView = new TextView(this);
        balanceView.setTextSize(26f);
        balanceView.setPadding(0, pad / 2, 0, pad);
        root.addView(balanceView);

        LinearLayout row = new LinearLayout(this);
        row.setOrientation(LinearLayout.HORIZONTAL);
        row.setGravity(Gravity.CENTER_VERTICAL);

        typeSpinner = new Spinner(this);
        ArrayAdapter<String> adapter = new ArrayAdapter<>(this, android.R.layout.simple_spinner_item, new String[]{"DEBIT", "CREDIT"});
        adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
        typeSpinner.setAdapter(adapter);
        row.addView(typeSpinner, new LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f));

        amountView = new EditText(this);
        amountView.setHint("Amount");
        amountView.setInputType(InputType.TYPE_CLASS_NUMBER);
        row.addView(amountView, new LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f));

        root.addView(row);

        submitButton = new Button(this);
        submitButton.setText("Submit Transaction");
        root.addView(submitButton);

        statusView = new TextView(this);
        statusView.setPadding(0, pad, 0, 0);
        root.addView(statusView);

        return root;
    }

    private void ensureDemoAccount() {
        new Thread(() -> {
            BankDatabase db = BankDatabase.getInstance(getApplicationContext());
            AccountDao dao = db.accountDao();
            AccountEntity existing = dao.getAccountSync(accountId);
            if (existing == null) {
                dao.upsert(new AccountEntity(accountId, "Demo Checking", "USD", 100_00L, System.currentTimeMillis()));
            }
        }).start();
    }

    private static long parseAmountToMinor(String s, String currencyCode) {
        if (s == null) return 0L;
        s = s.trim();
        if (s.isEmpty()) return 0L;
        try {
            int fraction = java.util.Currency.getInstance(currencyCode != null ? currencyCode : "USD").getDefaultFractionDigits();
            long value = Long.parseLong(s);
            long minor = value;
            for (int i = 0; i < fraction; i++) minor *= 10L;
            return minor;
        } catch (Exception e) {
            return 0L;
        }
    }
}